(function(){var $=window.jQuery;if(!$||!window.wp||!wp.media){return}var init=function(root){var $root=$(root);var $id=$root.find("input[name$=\"_image_id\"]");var $url=$root.find("input[name$=\"_image\"]");var $preview=$root.find(".fq-brand-image__preview");var $remove=$root.find(".fq-brand-image__remove");var setPreview=function(src){$preview.empty();if(src){$preview.append($("<img>").attr("src",src).attr("alt",""));$remove.removeClass("fq-brand-image__remove--hidden")}else{$remove.addClass("fq-brand-image__remove--hidden")}};var bootstrap=function(){var src=$preview.attr("data-fq-src")||$url.val()||"";setPreview(src)};bootstrap();$root.on("click",".fq-brand-image__upload",function(e){e.preventDefault();var frame=wp.media({title:"Seleccionar imagen",button:{text:"Usar esta imagen"},multiple:false});frame.on("select",function(){var att=frame.state().get("selection").first();if(!att){return}var json=att.toJSON();$id.val(json.id||"");$url.val(json.url||"");var thumb=json.sizes&&json.sizes.thumbnail?json.sizes.thumbnail.url:json.url;setPreview(thumb||json.url||"")});frame.open()});$root.on("click",".fq-brand-image__remove",function(e){e.preventDefault();$id.val("");$url.val("");setPreview("")})};$(function(){$(".fq-brand-image").each(function(){init(this)})})})();
